const items = $input.all();
const today = new Date().toISOString().split('T')[0];

if (!items || items.length === 0) {
  return [{ json: { message: ':white_check_mark: *Daily Aging Report -- ' + today + '*\nNo unpaid invoices older than 30 days found today.' } }];
}

const totalAccounts = items.length;
const grandTotal = items.reduce((sum, item) => sum + (item.json.total_outstanding || 0), 0);

let rows = '';
const maxRows = 20;
const displayed = items.slice(0, maxRows);

for (const item of displayed) {
  const d = item.json;
  const accountId = d.mongo_account_id || 'N/A';
  const count = d.invoice_count || 0;
  const amount = '$' + Number(d.total_outstanding).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  const oldest = d.oldest_invoice_date || 'N/A';
  rows += '\n| ' + accountId + ' | ' + count + ' | ' + amount + ' | ' + oldest + ' |';
}

const moreNote = items.length > maxRows ? '\n_...and ' + (items.length - maxRows) + ' more accounts not shown._' : '';

const message = ':rotating_light: *Daily Aging Report -- Unpaid Invoices (30+ days)*\n*Date:* ' + today + '\n*Accounts with overdue balance:* ' + totalAccounts + '\n*Grand Total Outstanding:* $' + grandTotal.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) + '\n\n*Top Accounts by Outstanding Balance:*\n| Account ID | Invoices | Outstanding | Oldest Invoice |\n|------------|----------|-------------|----------------|' + rows + moreNote;

return [{ json: { message } }];
